n, c = map(int, input().split())

d = [list(map(int, input().split())) for _ in range(c)]

c = [list(map(int, input().split())) for _ in range(n)]

ans = 0

for i in range(n):
    for j in range(n):
        ans += d[c[i][j]-1][c[i][j]-1]

        for x in range(n):
            for y in range(n):
                if (i+j)%3 == (x+y)%3:
                    if c[i][j] == c[x][y]:
                        ans += d[c[i][j]-1][c[x][y]-1]
                else:
                    if c[i][j] != c[x][y]:
                        ans += d[c[i][j]-1][c[x][y]-1]

print(ans)
